  label   String
  /// Short prefix of the plaintext (first 12 chars) — shown in UI for identification.
  prefix  String
  /// bcrypt hash of the full plaintext key. Never store plaintext.
  keyHash String
  /// Comma-separated scopes (e.g. "upload:write"). Empty = full founder scope.
  scopes  String @default("")

  createdAt  DateTime  @default(now())
  lastUsedAt DateTime?
  revokedAt  DateTime?

  founder      Founder      @relation(fields: [founderId], references: [id], onDelete: Cascade)
  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)

  @@index([organizationId])
  @@index([founderId])
  @@index([prefix])
}

