  idTextMap: Record<string, string>;
  sources: { uploadId: string; title: string; sourceType: string }[];
}) {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: "1.5rem" }}>
      <blockquote
        style={{
          margin: 0,
          padding: "1rem 1.25rem",
