function ExpandableIdList({
  label,
  ids,
  idTextMap,
}: {
  label: string;
  ids: string[];
  idTextMap: Record<string, string>;
}) {
  return (
    <details
      style={{
        padding: "0.75rem 1rem",
        border: "1px solid var(--border)",
        borderRadius: 2,
      }}
